class Solution:
    def averageOfLevels(self, root):
        sums = {}
        counts = {}
        def walk(node, depth):
            if not node:
                return
            sums[depth] = sums.get(depth, 0) + node.val
            counts[depth] = counts.get(depth, 0) + 1
            walk(node.left, depth + 1)
            walk(node.right, depth + 1)
        walk(root, 0)
        return [sums[d] / counts[d] for d in sorted(sums)]

