class Solution:
    def averageOfLevels(self, root):
        res = []
        level = [root] if root else []
        while level:
            total = sum(n.val for n in level)
            res.append(total / len(level))
            nxt = []
            for n in level:
                if n.left:
                    nxt.append(n.left)
                if n.right:
                    nxt.append(n.right)
            level = nxt
        return res

