var averageOfLevels = function(root) {
    const res = [];
    let level = root ? [root] : [];
    while (level.length) {
        let total = 0;
        for (const n of level) total += n.val;
        res.push(total / level.length);
        const nxt = [];
        for (const n of level) {
            if (n.left) nxt.push(n.left);
            if (n.right) nxt.push(n.right);
        }
        level = nxt;
    }
    return res;
};
